Use ASP.NET Core's **`WebApplicationFactory<T>`** from `Microsoft.AspNetCore.Mvc.Testing`. It spins up an in-memory test host — no real ports, no real server.

**1. Add the NuGet package:**
```
dotnet add package Microsoft.AspNetCore.Mvc.Testing
```

**2. Write a test class:**
```csharp
public class McpIntegrationTests : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly HttpClient _client;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test-client", version = "1.0" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2.0", body.GetProperty("jsonrpc").GetString());
        Assert.True(body.TryGetProperty("result", out var result));
        Assert.True(result.TryGetProperty("capabilities", out _));
    }

    [Fact]
    public async Task ToolsList_ReturnsRegisteredTools()
    {
        // Initialize first (MCP requires it)
        await InitializeSession();

        var request = new { jsonrpc = "2.0", id = 2, method = "tools/list" };
        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        var tools = body.GetProperty("result").GetProperty("tools");
        Assert.True(tools.GetArrayLength() > 0);
    }

    private async Task InitializeSession()
    {
        var init = new
        {
            jsonrpc = "2.0", id = 0, method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test", version = "1.0" }
            }
        };
        await _client.PostAsJsonAsync("/mcp", init);
    }
}
```

**Key points:**

- **`WebApplicationFactory<Program>`** boots your real `Program` class in-memory — full middleware pipeline, DI, routing, all of it.
- **`CreateClient()`** returns an `HttpClient` that talks to the in-memory host (no TCP).
- You can override services (e.g., swap a real DB for an in-memory one) via `factory.WithWebHostBuilder(b => b.ConfigureServices(...))`.
- If your MCP endpoint uses **SSE** for streaming, use `GetStreamAsync` and read with a `StreamReader` line-by-line.
- Make sure `Program` is accessible to your test project (add `InternalsVisibleTo` or use a `public partial class Program { }` marker).
